import {RefObject, useEffect, useRef} from 'react';

import {useForceUpdate} from '../../hooks/use-force-update';

/**
 * Represents the 3D camera state with all position and orientation parameters.
 */
export type CameraState3D = {
  center: google.maps.LatLngAltitudeLiteral;
  range: number;
  heading: number;
  tilt: number;
  roll: number;
};

export type CameraStateRef3D = RefObject<CameraState3D>;

const DEFAULT_CAMERA_STATE: CameraState3D = {
  center: {lat: 0, lng: 0, altitude: 0},
  range: 0,
  heading: 0,
  tilt: 0,
  roll: 0
};

/**
 * Camera property names that correspond to gmp-*change events.
 */
const CAMERA_PROPS = ['center', 'range', 'heading', 'tilt', 'roll'] as const;
type CameraProp = (typeof CAMERA_PROPS)[number];

/**
 * Updates the camera state ref with values from the map element.
 */
function updateCameraState(
  map3d: google.maps.maps3d.Map3DElement,
  ref: CameraStateRef3D,
  prop: CameraProp
) {
  const value = map3d[prop];

  if (value == null) return;

  if (prop === 'center') {
    // The center property returns a LatLngAltitude object, convert to literal
    const center = value as google.maps.LatLngAltitude;
    ref.current.center = center.toJSON
      ? center.toJSON()
      : (center as google.maps.LatLngAltitudeLiteral);
  } else {
    ref.current[prop] = value as number;
  }
}

/**
 * Creates a mutable ref object to track the last known state of the 3D map camera.
 * This is used in `useMap3DCameraParams` to reduce stuttering by avoiding updates
 * of the map camera with values that have already been processed.
 *
 * @internal
 */
export function useTrackedCameraStateRef3D(
  map3d: google.maps.maps3d.Map3DElement | null
): CameraStateRef3D {
  const forceUpdate = useForceUpdate();
  const ref = useRef<CameraState3D>({...DEFAULT_CAMERA_STATE});

  useEffect(() => {
    if (!map3d) return;

    const listeners: (() => void)[] = [];

    for (const prop of CAMERA_PROPS) {
      const eventName = `gmp-${prop}change`;

      const handler = () => {
        updateCameraState(map3d, ref, prop);
        forceUpdate();
      };

      map3d.addEventListener(eventName, handler);
      listeners.push(() => map3d.removeEventListener(eventName, handler));
    }

    return () => {
      for (const removeListener of listeners) {
        removeListener();
      }
    };
  }, [map3d, forceUpdate]);

  return ref;
}
import {Ref, useEffect, useState} from 'react';

import {useCallbackRef} from '../../hooks/use-callback-ref';
import {useMapsLibrary} from '../../hooks/use-maps-library';
import {
  CameraStateRef3D,
  useTrackedCameraStateRef3D
} from './use-tracked-camera-state-ref-3d';
import {Map3DProps} from './index';

/**
 * Hook to manage the Map3DElement instance lifecycle.
 *
 * Handles:
 * - Waiting for the 'maps3d' library to load
 * - Waiting for the 'gmp-map-3d' custom element to be defined
 * - Creating a callback ref for the element
 * - Applying initial options when the element is ready
 * - Tracking camera state
 *
 * @internal
 */
export function useMap3DInstance(
  props: Map3DProps
): readonly [
  map3d: google.maps.maps3d.Map3DElement | null,
  containerRef: Ref<HTMLDivElement>,
  map3dRef: Ref<google.maps.maps3d.Map3DElement>,
  cameraStateRef: CameraStateRef3D,
  isReady: boolean
] {
  const maps3dLib = useMapsLibrary('maps3d');
  const [customElementReady, setCustomElementReady] = useState(false);
  const [, containerRef] = useCallbackRef<HTMLDivElement>();
  const [map3d, map3dRef] = useCallbackRef<google.maps.maps3d.Map3DElement>();
  const cameraStateRef = useTrackedCameraStateRef3D(map3d);

  useEffect(() => {
    customElements.whenDefined('gmp-map-3d').then(() => {
      setCustomElementReady(true);
    });
  }, []);

  // Apply initial options once when the element is first available
  useEffect(
    () => {
      if (!map3d) return;

      const {
        center,
        heading,
        tilt,
        range,
        roll,
        defaultCenter,
        defaultHeading,
        defaultTilt,
        defaultRange,
        defaultRoll,
        // Non-element props to exclude
        id,
        style,
        className,
        children,
        onCenterChanged,
        onHeadingChanged,
        onTiltChanged,
        onRangeChanged,
        onRollChanged,
        onCameraChanged,
        onClick,
        onSteadyChange,
        onAnimationEnd,
        onError,
        mode,
        gestureHandling,
        ...elementOptions
      } = props;

      const initialCenter = center ?? defaultCenter;
      const initialHeading = heading ?? defaultHeading;
      const initialTilt = tilt ?? defaultTilt;
      const initialRange = range ?? defaultRange;
      const initialRoll = roll ?? defaultRoll;

      const initialOptions: Partial<google.maps.maps3d.Map3DElementOptions> = {
        ...elementOptions
      };

      if (initialCenter) initialOptions.center = initialCenter;
      if (initialHeading !== undefined) initialOptions.heading = initialHeading;
      if (initialTilt !== undefined) initialOptions.tilt = initialTilt;
      if (initialRange !== undefined) initialOptions.range = initialRange;
      if (initialRoll !== undefined) initialOptions.roll = initialRoll;

      Object.assign(map3d, initialOptions);
    },
    // this effect should only run when the map3d element first becomes
    // available, so we skip re-running it when other props change.
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [map3d]
  );

  const isReady = !!maps3dLib && customElementReady;

  return [map3d, containerRef, map3dRef, cameraStateRef, isReady] as const;
}
