  usePropBinding(marker, 'extruded', extruded);
  usePropBinding(marker, 'label', label);
  usePropBinding(marker, 'sizePreserved', sizePreserved);
  usePropBinding(marker, 'zIndex', zIndex);
  usePropBinding(marker, 'title', title ?? '');

