export const Rectangle = forwardRef(
  (props: RectangleProps, ref: RectangleRef) => {
    const rectangle = useRectangle(props);

    useImperativeHandle(ref, () => rectangle as google.maps.Rectangle, [
      rectangle
    ]);

    return <></>;
  }
